package com.parkhub.app.ui.screens

import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import com.parkhub.app.data.FahrerDao
import com.parkhub.app.model.Fahrer
import kotlinx.coroutines.flow.Flow

class FlotteViewModel(private val fahrerDao: FahrerDao) : ViewModel() {
    val fahrerList: Flow<List<Fahrer>> = fahrerDao.getAllFahrer()
}

class FlotteViewModelFactory(private val fahrerDao: FahrerDao) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(FlotteViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return FlotteViewModel(fahrerDao) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

package com.parkhub.app.ui.screens
import androidx.lifecycle.ViewModel import com.parkhub.app.model.fahrerListe import kotlinx.coroutines.flow.Flow import kotlinx.coroutines.flow.flowOf
class FlotteViewModel : ViewModel() { val fahrerList: Flow<List<Any>> = flowOf(fahrerListe) }
